const e=JSON.parse('{"key":"v-052ce8ba","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/12-%E8%9C%A1%E7%83%9B%E5%9B%BE%E4%B8%8E%E8%89%BE%E7%95%A5%E7%89%B9%E6%B3%A2%E6%B5%AA%E7%90%86%E8%AE%BA.html","title":"蜡烛图与艾略特波浪理论","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["艾略特波浪理论"],"order":12,"description":"蜡烛图与艾略特波浪理论 应用艾略特波浪理论的技术分析师为数众多，广泛分布在各种市场领域内。这一理论既适用于日内价格图表，也适用于以年为时间单位的超长期图表。在本章，我们只准备对艾略特波浪理论作一点粗浅的入门性介绍。如果详细介绍艾略特波浪理论的市场分析方法，恐怕非得专门写一本书不可。 艾略特波浪理论的基本概念 image-20240127220939428 艾略特波浪理论是R.N.艾略特在本世纪初发现的。他从市场各个方面的特性中注意到，价格运动是通过下述基本过程形成的：先是五浪上涨，然后跟着调整性的三浪下跌。如图16.1所示，上述八浪组成了一个完整的市场周期。其中，1浪、3浪、5浪称为主浪（也称推进浪），2浪和4浪称为调整浪（也称次浪）。虽然在图16.1中，艾略特波浪的数浪情况反映出一个上涨的市场，但是，同样的概念也适用于下跌的市场。于是，在下降趋势的市场上，主浪的方向将是向下倾斜的，而调整浪则向上倾斜，与主要趋势方向相反。艾略特另一方面的重大贡献是，将菲波纳奇数列引入了市场预测研究。因为菲波纳奇比数可以用来推算下一浪的价格目标，所以数浪技术与菲波纳奇比数是相辅相成的。举例来说，我们可以将1浪的高度乘以1.618，由此推测3浪的高度；4浪可能将3浪的运动幅度往回调整38.2%，或者50%；如此等等。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E6%97%A5%E6%9C%AC%E8%9C%A1%E7%83%9B%E5%9B%BE%E6%8A%80%E6%9C%AF/12-%E8%9C%A1%E7%83%9B%E5%9B%BE%E4%B8%8E%E8%89%BE%E7%95%A5%E7%89%B9%E6%B3%A2%E6%B5%AA%E7%90%86%E8%AE%BA.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"蜡烛图与艾略特波浪理论"}],["meta",{"property":"og:description","content":"蜡烛图与艾略特波浪理论 应用艾略特波浪理论的技术分析师为数众多，广泛分布在各种市场领域内。这一理论既适用于日内价格图表，也适用于以年为时间单位的超长期图表。在本章，我们只准备对艾略特波浪理论作一点粗浅的入门性介绍。如果详细介绍艾略特波浪理论的市场分析方法，恐怕非得专门写一本书不可。 艾略特波浪理论的基本概念 image-20240127220939428 艾略特波浪理论是R.N.艾略特在本世纪初发现的。他从市场各个方面的特性中注意到，价格运动是通过下述基本过程形成的：先是五浪上涨，然后跟着调整性的三浪下跌。如图16.1所示，上述八浪组成了一个完整的市场周期。其中，1浪、3浪、5浪称为主浪（也称推进浪），2浪和4浪称为调整浪（也称次浪）。虽然在图16.1中，艾略特波浪的数浪情况反映出一个上涨的市场，但是，同样的概念也适用于下跌的市场。于是，在下降趋势的市场上，主浪的方向将是向下倾斜的，而调整浪则向上倾斜，与主要趋势方向相反。艾略特另一方面的重大贡献是，将菲波纳奇数列引入了市场预测研究。因为菲波纳奇比数可以用来推算下一浪的价格目标，所以数浪技术与菲波纳奇比数是相辅相成的。举例来说，我们可以将1浪的高度乘以1.618，由此推测3浪的高度；4浪可能将3浪的运动幅度往回调整38.2%，或者50%；如此等等。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-01-27T15:35:20.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"艾略特波浪理论"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-01-27T15:35:20.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"蜡烛图与艾略特波浪理论\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-01-27T15:35:20.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"艾略特波浪理论的基本概念","slug":"艾略特波浪理论的基本概念","link":"#艾略特波浪理论的基本概念","children":[]},{"level":2,"title":"艾略特波浪理论与蜡烛图","slug":"艾略特波浪理论与蜡烛图","link":"#艾略特波浪理论与蜡烛图","children":[]}],"git":{"createdTime":1706369720000,"updatedTime":1706369720000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":6.04,"words":1811},"filePathRelative":"证券交易/日本蜡烛图技术/12-蜡烛图与艾略特波浪理论.md","localizedDate":"2024年1月17日","excerpt":"<h1> 蜡烛图与艾略特波浪理论</h1>\\n<p>应用艾略特波浪理论的技术分析师为数众多，广泛分布在各种市场领域内。这一理论既适用于日内价格图表，也适用于以年为时间单位的超长期图表。在本章，我们只准备对艾略特波浪理论作一点粗浅的入门性介绍。如果详细介绍艾略特波浪理论的市场分析方法，恐怕非得专门写一本书不可。</p>\\n<h2> 艾略特波浪理论的基本概念</h2>\\n<figure><figcaption>image-20240127220939428</figcaption></figure>\\n<p>艾略特波浪理论是R.N.艾略特在本世纪初发现的。他从市场各个方面的特性中注意到，价格运动是通过下述基本过程形成的：先是五浪上涨，然后跟着调整性的三浪下跌。如图16.1所示，上述八浪组成了一个完整的市场周期。其中，1浪、3浪、5浪称为主浪（也称推进浪），2浪和4浪称为调整浪（也称次浪）。虽然在图16.1中，艾略特波浪的数浪情况反映出一个上涨的市场，但是，同样的概念也适用于下跌的市场。于是，在下降趋势的市场上，主浪的方向将是向下倾斜的，而调整浪则向上倾斜，与主要趋势方向相反。艾略特另一方面的重大贡献是，将菲波纳奇数列引入了市场预测研究。因为菲波纳奇比数可以用来推算下一浪的价格目标，所以数浪技术与菲波纳奇比数是相辅相成的。举例来说，我们可以将1浪的高度乘以1.618，由此推测3浪的高度；4浪可能将3浪的运动幅度往回调整38.2%，或者50%；如此等等。</p>","autoDesc":true}');export{e as data};
